export type TestPriority = "critical" | "high" | "medium" | "low";
export type TestStatus   = "untested" | "pass" | "fail" | "blocked" | "skipped";
export type TestRole     = "Signed Out" | "Regular User" | "Admin" | "Contributor" | "Facility User" | "Tester";

export type QASection = {
  num: number;
  title: string;
};

export type QATest = {
  id: string;           // e.g. "1.1", "7.3"
  sectionNum: number;
  priority: TestPriority;
  roles: TestRole[];    // Role Switcher position(s) needed to perform this test
  title: string;
  description: string;
};

