// Helper: tests grouped by section
export function getTestsBySection(): Map<number, QATest[]> {
  const map = new Map<number, QATest[]>();
  for (const test of QA_TESTS) {
    const arr = map.get(test.sectionNum) ?? [];
    arr.push(test);
    map.set(test.sectionNum, arr);
  }
  return map;
}

